import java.util.HashMap;

public class Solution {
    public boolean canEqualFrequency(String word) {
        HashMap<Character, Integer> freq = new HashMap<>();
        for (char c : word.toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }

        HashMap<Integer, Integer> count_freq = new HashMap<>();
        int a = -1, b = -1;
        int acount = 0, bcount = 0;

        for (int f : freq.values()) {
            if (!count_freq.containsKey(f)) {
                if (a == -1) {
                    a = f;
                    acount++;
                } else if (b == -1) {
                    b = f;
                    bcount++;
                } else {
                    return false; // More than 2 unique frequencies
                }
            } else {
                int existingCount = count_freq.get(f);
                if (existingCount > 0 && a != -1 && b != -1) {
                    return false; // More than 2 unique frequencies
                }

                if (a == f) {
                    acount += existingCount;
                } else if (b == f) {
                    bcount += existingCount;
                }
            }
        }

        count_freq.put(a, acount);
        count_freq.put(b, bcount);

        return (acount == 1 && (a - 1 == b || a == 1)) || (bcount == 1 && (b - 1 == a || b == 1));
    }
}
